/*
 * Global Design System
 * Matches the modern, image-driven hero style of the reference tennis academy design.
 */

:root {
  /* Brand & Palette */
  --color-primary: #7B3FE4; /* purple accent */
  --color-primary-strong: #5E1FE0;
  --color-secondary-yellow: #F5D94C;

  --color-neutral-900: #000000;
  --color-neutral-800: #111827;
  --color-neutral-200: #E5E7EB;
  --color-neutral-100: #F9FAFB;
  --color-white: #FFFFFF;

  --color-success: #16A34A;
  --color-error: #DC2626;
  --color-warning: #F59E0B;
  --color-info: #2563EB;

  /* Typography */
  --font-heading: "Space Grotesk", Helvetica, sans-serif;
  --font-body: "Source Sans 3", Arial, sans-serif;
  --font-code: "Source Code Pro", monospace;

  --font-size-h1: 2.75rem; /* ~44px on desktop */
  --font-size-h2: 2rem;    /* 32px */
  --font-size-h3: 1.5rem;  /* 24px */
  --font-size-body: 1rem;  /* 16px */
  --font-size-small: 0.8125rem; /* 13px */

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale (4 / 8 / 16 / 24 / 32 / 48 / 64) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Layout */
  --site-max-width: 1200px;
  --header-height-desktop: 80px;
  --header-overlay-gradient: linear-gradient(180deg, rgba(0, 0, 0, 0.9) 0%, rgba(0, 0, 0, 0.85) 55%, rgba(0, 0, 0, 0.0) 100%);

  /* Elevation */
  --shadow-soft: 0 10px 25px rgba(0, 0, 0, 0.08);
}

/* Base layout */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: 16px;
  scroll-behavior: smooth;
}

body.site {
  margin: 0;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  background-color: var(--color-neutral-900);
  color: var(--color-neutral-200);
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:focus-visible {
  outline: 2px solid var(--color-primary);
  outline-offset: 2px;
}

.container {
  width: 100%;
  max-width: var(--site-max-width);
  margin-left: auto;
  margin-right: auto;
  padding-left: var(--space-4);
  padding-right: var(--space-4);
}

.site-content {
  flex: 1 0 auto;
  padding-top: calc(var(--header-height-desktop) + var(--space-6)); /* keep content clear of fixed header */
  padding-bottom: var(--space-7);
}

/* Header */

.site-header {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 50;
  height: var(--header-height-desktop);
  background: var(--header-overlay-gradient);
  color: var(--color-white);
  display: flex;
  align-items: stretch;
}

/* Centered purple accent bar at the very top, matching the reference */
.site-header::before {
  content: "";
  position: absolute;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 56px;
  height: 3px;
  background-color: var(--color-primary);
  border-radius: 999px;
}

.site-header__inner {
  display: flex;
  align-items: center;
  justify-content: center;
}

/* Primary navigation */

.main-nav {
  width: 100%;
}

.main-nav__list {
  margin: 0;
  padding: 0;
  list-style: none;
  display: flex;
  justify-content: center;
  align-items: center;
  gap: var(--space-5);
}

.main-nav__item {
  position: relative;
}

.main-nav__link {
  display: inline-block;
  padding: 0;
  margin-top: 32px; /* centers vertically within header and leaves space for accent underline */
  margin-bottom: 16px;
  font-family: var(--font-heading);
  font-size: var(--font-size-small);
  font-weight: 600;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--color-white);
  text-decoration: none;
  position: relative;
  transition: color 0.2s ease;
}

/* Purple underline indicator under active/hover nav item */
.main-nav__link::after {
  content: "";
  position: absolute;
  left: 50%;
  transform: translateX(-50%);
  bottom: -10px;
  width: 32px;
  height: 3px;
  border-radius: 999px;
  background-color: var(--color-primary);
  opacity: 0;
  transition: opacity 0.2s ease;
}

.main-nav__link.is-active,
.main-nav__link:hover,
.main-nav__link:focus-visible {
  color: var(--color-white);
}

.main-nav__link.is-active::after,
.main-nav__link:hover::after,
.main-nav__link:focus-visible::after {
  opacity: 1;
}

/* Footer */

.site-footer {
  margin-top: auto;
  background-color: var(--color-neutral-800);
  color: var(--color-neutral-200);
  padding-top: var(--space-6);
  padding-bottom: var(--space-6);
  border-top: 1px solid rgba(229, 231, 235, 0.12);
}

.site-footer__inner {
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  gap: var(--space-4);
}

.site-footer__brand {
  max-width: 480px;
}

.site-footer__title {
  margin: 0 0 var(--space-1) 0;
  font-family: var(--font-heading);
  font-weight: 700;
  font-size: 1rem;
  letter-spacing: 0.16em;
  text-transform: uppercase;
}

.site-footer__subtitle {
  margin: 0;
  font-size: 0.875rem;
  color: rgba(229, 231, 235, 0.8);
}

.footer-nav {
  width: 100%;
}

.footer-nav__list {
  margin: 0;
  padding: 0;
  list-style: none;
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: var(--space-3);
}

.footer-nav__item {
  font-size: 0.875rem;
}

.footer-nav__link {
  position: relative;
  padding-bottom: 2px;
  color: rgba(229, 231, 235, 0.8);
  text-decoration: none;
  transition: color 0.2s ease;
}

.footer-nav__link::after {
  content: "";
  position: absolute;
  left: 0;
  bottom: 0;
  width: 100%;
  height: 1px;
  background-color: var(--color-primary);
  transform: scaleX(0);
  transform-origin: left;
  transition: transform 0.2s ease;
}

.footer-nav__link:hover,
.footer-nav__link:focus-visible {
  color: var(--color-white);
}

.footer-nav__link:hover::after,
.footer-nav__link:focus-visible::after {
  transform: scaleX(1);
}

.site-footer__meta {
  font-size: 0.75rem;
  color: rgba(229, 231, 235, 0.6);
}

.site-footer__copyright {
  margin: 0;
}

/* Responsive adjustments */

@media (max-width: 960px) {
  .main-nav__list {
    gap: var(--space-3);
    flex-wrap: wrap;
  }

  .main-nav__link {
    margin-top: 24px;
    margin-bottom: 12px;
  }

  .site-content {
    padding-top: calc(var(--header-height-desktop) + var(--space-5));
  }
}

@media (max-width: 640px) {
  :root {
    --header-height-desktop: 96px; /* slightly taller to accommodate wrapped nav */
  }

  .site-header__inner {
    justify-content: center;
  }

  .main-nav__list {
    gap: var(--space-2);
  }

  .main-nav__link {
    font-size: 0.75rem;
    letter-spacing: 0.16em;
  }

  .footer-nav__list {
    gap: var(--space-2);
  }
}
